        if (err != cudaSuccess)
        {
            printf("Error: Failed to write to d_resultList_first_buff source array!\n");
            exit(1);
        }

        err = cudaMemcpy(d_origList_first_buff, d_origList, listsize*sizeof(float), cudaMemcpyHostToDevice);
        if (err != cudaSuccess)
        {
            printf("Error: Failed to write to d_origList_first_buff source array!\n");
            exit(1);
        }

        dim3 blockDimPass(local[0], 1, 1);
        dim3 gridDimPass(grid0, 1, 1);

        mergeSortPass<<<gridDimPass, blockDimPass>>>(d_origList_first_buff, d_resultList_first_buff, nrElems, threadsPerDiv, constStartAddr_device);
        if (err != cudaSuccess)
        {
            printf("Error: Failed to execute mergePass kernel!\n");
            exit(1);
        }

        cudaDeviceSynchronize();
        err = cudaMemcpy(d_resultList, d_resultList_first_buff, listsize*sizeof(float), cudaMemcpyDeviceToHost);
        if (err != cudaSuccess)
        {
            printf("Error: Failed to read prefix output array! %d\n", err);
            exit(1);
        }
#ifdef TIMING
        kernel_time += 0;
#endif

        cudaEventCreate(&start);
        cudaEventCreate(&end);
        cudaEventRecord(start);
        cudaEventRecord(end);
        cudaEventSynchronize(end);
        cudaEventElapsedTime(&elapsed_time, start, end);
        mergesum += elapsed_time / 1000.0;
        mergePassTime += elapsed_time / 1000.0;
        printf("Merge Pass Kernel Iteration Time: %0.3f \n", elapsed_time);
        cudaEventDestroy(start);
        cudaEventDestroy(end);
		nrElems *= 2;
		floatsperthread = (nrElems*4);

		if(threadsPerDiv == 1) break;
	}
    printf("Merge Pass Kernel Time: %0.3f \n", mergePassTime);
#ifdef  TIMING
    gettimeofday(&tv_mem_alloc_start, NULL);
#endif
    err = cudaMalloc(&finalStartAddr_device, (divisions+1)*sizeof(int));
    if (err != cudaSuccess)
    {
        printf("Error: Failed to allocate finalStartAddr!\n");
        exit(1);
    }
    err = cudaMalloc(&nullElems_device, (divisions)*sizeof(int));
    if (err != cudaSuccess)
    {
        printf("Error: Failed to allocate nullElems!\n");
        exit(1);
    }
#ifdef  TIMING
    gettimeofday(&tv_mem_alloc_end, NULL);
    tvsub(&tv_mem_alloc_end, &tv_mem_alloc_start, &tv);
    mem_alloc_time += tv.tv_sec * 1000.0 + (float) tv.tv_usec / 1000.0;
#endif

    err = cudaMemcpy(finalStartAddr_device, origOffsets, (divisions+1)*sizeof(int), cudaMemcpyHostToDevice);
    if (err != cudaSuccess)
    {
        printf("Error: Failed to write to finalStartAddr source array!\n");
        exit(1);
    }

    err = cudaMemcpy(nullElems_device, nullElements, (divisions)*sizeof(int), cudaMemcpyHostToDevice);
    if (err != cudaSuccess)
    {
        printf("Error: Failed to write to nullElements source array!\n");
        exit(1);
    }
#ifdef MERGE_WG_SIZE_0
    local[0] = MERGE_WG_SIZE_0;
#else
    local[0] = 256;
#endif
	int grid0 = ((largestSize%local[0]) == 0) ?
    largestSize/local[0] :
    (largestSize/local[0]) + 1;
	int grid1 = divisions;

    dim3 blockDimPack(local[0], 1, 1);
    dim3 gridDimPack(grid0, grid1, 1);

    err = cudaMemcpy(d_res, d_resultList, listsize*sizeof(float), cudaMemcpyHostToDevice);
    if (err != cudaSuccess)
    {
        printf("Error: Failed to write to d_res source array!\n");
        exit(1);
    }

    err = cudaMemcpy(d_orig, d_origList, listsize*sizeof(float), cudaMemcpyHostToDevice);
    if (err != cudaSuccess)
    {
        printf("Error: Failed to write to d_orig source array!\n");
        exit(1);
    }

    mergepack<<<gridDimPack, blockDimPack>>>(d_orig, d_res, constStartAddr_device, nullElems_device, finalStartAddr_device);
    if (err != cudaSuccess)
    {
        printf("Error: Failed to execute merge pack kernel!\n");
        exit(1);
    }
#ifdef TIMING
    kernel_time += 0;
#endif

    cudaDeviceSynchronize();
    cudaEventCreate(&start);
    cudaEventCreate(&end);
    cudaEventRecord(start);
    cudaEventRecord(end);
    cudaEventSynchronize(end);
    cudaEventElapsedTime(&elapsed_time, start, end);
    mergesum += elapsed_time / 1000.0;
    printf("Merge Pack Kernel Time: %0.3f \n", elapsed_time);
    cudaEventDestroy(start);
    cudaEventDestroy(end);

    err = cudaMemcpy(d_origList, d_orig, listsize*sizeof(float), cudaMemcpyDeviceToHost);
    if (err != cudaSuccess)
    {
        printf("Error: Failed to read origList array! %d\n", err);
        exit(1);
    }

	free(startaddr);
	return d_origList;

}

double getMergeTime() {
  return mergesum;
}
